import React, { useEffect, useState, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { 
  Box, 
  Container, 
  Grid, 
  Paper, 
  Typography, 
  Button, 
  Card, 
  CardContent, 
  Divider,
  List,
  ListItem,
  ListItemText,
  ListItemAvatar,
  Avatar,
  CircularProgress,
  Alert
} from '@mui/material';
import {
  AccountBalanceWallet,
  Send,
  Chat,
  SwapHoriz,
  Assessment,
  ArrowUpward,
  ArrowDownward,
  Error
} from '@mui/icons-material';
import api from '../utils/api';
import { useAuth } from '../context/AuthContext';

const Dashboard = () => {
  const { currentUser, isAuthenticated } = useAuth();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [wallets, setWallets] = useState([]);
  const [transactions, setTransactions] = useState([]);
  const [error, setError] = useState(null);
  const [totalBalance, setTotalBalance] = useState(0);
  const [debug, setDebug] = useState({});

  // Use ref to track if currentUser has changed in a meaningful way
  const prevUserIdRef = useRef(null);
  const hasUserChanged = currentUser?.id !== prevUserIdRef.current;

  useEffect(() => {
    // Store current user ID in ref
    prevUserIdRef.current = currentUser?.id;

    const fetchDashboardData = async () => {
      console.log('Dashboard: Starting data fetch. User ID:', currentUser?.id);

      // Check if we recently fetched data to prevent excessive API calls
      const lastFetch = sessionStorage.getItem('dashboard_last_fetch');
      const currentTime = Date.now();

      // Only refetch if more than 30 seconds have passed since last fetch
      // OR if this is the first load OR if user has changed
      const shouldRefetch = !lastFetch || 
                            (currentTime - parseInt(lastFetch)) > 30000 || 
                            hasUserChanged;

      if (!shouldRefetch) {
        console.log('Dashboard: Using cached data, skipping API requests');
        setLoading(false);
        return;
      }

      console.log('Dashboard: Fetching fresh data...');
      sessionStorage.setItem('dashboard_last_fetch', currentTime.toString());

      setLoading(true);
      setError(null);
      let debugData = { 
        attempts: {}, 
        responses: {},
        currentUser: currentUser ? { ...currentUser, id: currentUser.id } : null,
        isAuthenticated,
        timestamp: new Date().toISOString()
      };

      try {
        // Fetch wallets
        try {
          console.log('Fetching wallet data...');
          let walletData = [];

          // Try user-specific wallet endpoint if we have a user ID
          if (currentUser && currentUser.id) {
            try {
              debugData.attempts.userWallet = `Attempting to fetch wallet for user ${currentUser.id}`;
              console.log(`Dashboard: Fetching wallet for user ${currentUser.id}`);
              const walletsResponse = await api.get(`/wallet/${currentUser.id}`);
              console.log('User specific wallet response:', walletsResponse.data);
              debugData.responses.userWallet = walletsResponse.data;

              // Convert to array if single object
              if (!Array.isArray(walletsResponse.data)) {
                walletData = [walletsResponse.data];
              } else {
                walletData = walletsResponse.data;
              }
            } catch (userWalletErr) {
              debugData.errors = debugData.errors || {};
              debugData.errors.userWallet = `Error: ${userWalletErr.message}`;
              console.warn('Could not fetch user-specific wallet, trying general endpoint:', userWalletErr);
            }
          }

          // If we couldn't get user wallets, try the general endpoint
          if (walletData.length === 0) {
            debugData.attempts.allWallets = "Attempting to fetch all wallets";
            console.log('Dashboard: Fetching all wallets as fallback');
            const generalWalletResponse = await api.get('/wallet/');
            console.log('General wallet response:', generalWalletResponse.data);
            debugData.responses.allWallets = generalWalletResponse.data;

            // If we get an array, filter for current user's wallet
            const allWallets = generalWalletResponse.data;
            if (Array.isArray(allWallets)) {
              if (currentUser && currentUser.id) {
                // Filter wallets for current user
                const userWallets = allWallets.filter(w => w.user_id === currentUser.id);
                if (userWallets.length > 0) {
                  walletData = userWallets;
                } else {
                  // If filtering returned no wallets, use all for demo purposes
                  walletData = allWallets;
                }
              } else {
                walletData = allWallets;
              }
            } else if (generalWalletResponse.data) {
              walletData = [generalWalletResponse.data];
            }
          }

          console.log('Dashboard: Setting wallet data:', walletData);
          setWallets(walletData || []);

          // Calculate total balance across all wallets
          const total = (walletData || []).reduce((sum, wallet) => 
            sum + parseFloat(wallet.fiat_balance || wallet.balance || 0), 0);
          setTotalBalance(total);

        } catch (walletErr) {
          debugData.errors = debugData.errors || {};
          debugData.errors.wallet = `Error: ${walletErr.message}`;
          console.error('Error fetching wallets:', walletErr);
          // Don't set an error here, just use empty wallet data
          setWallets([]);
          setTotalBalance(0);
        }

        // Fetch recent transactions
        try {
          console.log('Fetching transaction data...');
          let transactionsData = [];

          // Try user-specific transactions first
          if (currentUser && currentUser.id) {
            try {
              debugData.attempts.userTransactions = `Attempting to fetch transactions for user ${currentUser.id}`;
              const userTxResponse = await api.get(`/transaction/user/${currentUser.id}`);
              console.log('User transactions response:', userTxResponse.data);
              debugData.responses.userTransactions = userTxResponse.data;

              if (Array.isArray(userTxResponse.data)) {
                transactionsData = userTxResponse.data;
              } else if (userTxResponse.data && Array.isArray(userTxResponse.data.transactions)) {
                transactionsData = userTxResponse.data.transactions;
              }
            } catch (userTxErr) {
              debugData.errors = debugData.errors || {};
              debugData.errors.userTransactions = `Error: ${userTxErr.message}`;
              console.warn('Could not fetch user transactions, trying history endpoint:', userTxErr);

              try {
                debugData.attempts.transactionHistory = `Attempting to fetch transaction history for user ${currentUser.id}`;
                const historyResponse = await api.get(`/transaction/${currentUser.id}/history`);
                console.log('Transaction history response:', historyResponse.data);
                debugData.responses.transactionHistory = historyResponse.data;

                const sent = historyResponse.data?.sent_transactions || [];
                const received = historyResponse.data?.received_transactions || [];

                // Add a type property to distinguish transaction direction
                const sentWithType = sent.map(tx => ({ ...tx, type: 'SEND' }));
                const receivedWithType = received.map(tx => ({ ...tx, type: 'RECEIVE' }));

                transactionsData = [...sentWithType, ...receivedWithType];
              } catch (historyErr) {
                debugData.errors = debugData.errors || {};
                debugData.errors.transactionHistory = `Error: ${historyErr.message}`;
                console.warn('Could not fetch transaction history:', historyErr);
              }
            }
          }

          // If we still don't have transactions, try the general endpoint
          if (transactionsData.length === 0) {
            debugData.attempts.allTransactions = "Attempting to fetch all transactions";
            try {
              const generalTxResponse = await api.get('/transaction/');
              console.log('General transaction response:', generalTxResponse.data);
              debugData.responses.allTransactions = generalTxResponse.data;

              if (Array.isArray(generalTxResponse.data)) {
                // Filter for current user if we have a user ID
                if (currentUser && currentUser.id) {
                  transactionsData = generalTxResponse.data.filter(tx => 
                    tx.sender_id === currentUser.id || tx.recipient_id === currentUser.id
                  );
                } else {
                  transactionsData = generalTxResponse.data;
                }
              } else if (generalTxResponse.data && Array.isArray(generalTxResponse.data.transactions)) {
                transactionsData = generalTxResponse.data.transactions;
              }
            } catch (err) {
              debugData.errors = debugData.errors || {};
              debugData.errors.allTransactions = `Error: ${err.message}`;
              console.error('Error fetching general transactions:', err);
            }
          }

          // Process and format the transaction data
          const processedTransactions = transactionsData.map(tx => ({
            ...tx,
            formattedAmount: formatCurrency(tx.amount || tx.source_amount || 0, tx.currency || tx.source_currency || 'USD'),
            formattedDate: tx.timestamp ? formatDate(tx.timestamp) : 'N/A',
            type: determineTransactionType(tx, currentUser?.id)
          }));

          setTransactions(processedTransactions || []);

        } catch (txErr) {
          debugData.errors = debugData.errors || {};
          debugData.errors.transaction = `Error: ${txErr.message}`;
          console.error('Error fetching transactions:', txErr);
          // Don't set an error here, just use empty transaction data
          setTransactions([]);
        }

        setDebug(debugData);
      } catch (err) {
        console.error('Error fetching dashboard data:', err);
        setError('Failed to load dashboard data. Please try again.');
        setDebug({
          ...debug,
          lastError: err.message,
          errorStack: err.stack
        });
      } finally {
        setLoading(false);
      }
    };

    if (isAuthenticated) {
      fetchDashboardData();
    } else {
      setLoading(false);
    }
  }, [isAuthenticated, currentUser?.id]); // Only re-fetch when authentication status or user ID changes

  const determineTransactionType = (transaction, userId) => {
    if (transaction.type) return transaction.type;
    if (transaction.transaction_type) return transaction.transaction_type;

    // If we have the user ID, determine if it's a send or receive
    if (userId) {
      if (transaction.sender_id === userId) return 'SEND';
      if (transaction.recipient_id === userId) return 'RECEIVE';
    }

    // If no explicit type, try to infer from other properties
    if (transaction.from_wallet_id && transaction.to_wallet_id) {
      return 'TRANSFER';
    } else if (transaction.to_wallet_id) {
      return 'DEPOSIT';
    } else if (transaction.from_wallet_id) {
      return 'WITHDRAWAL';
    }

    return 'UNKNOWN';
  };

  const formatCurrency = (amount, currency = 'USD') => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency
    }).format(amount || 0);
  };

  const formatDate = (dateString) => {
    const options = { year: 'numeric', month: 'short', day: 'numeric' };
    return new Date(dateString).toLocaleDateString('en-US', options);
  };

  const getTransactionIcon = (type) => {
    const typeUpper = String(type).toUpperCase();
    if (typeUpper === 'DEPOSIT' || typeUpper === 'RECEIVE') return <ArrowDownward color="success" />;
    if (typeUpper === 'WITHDRAWAL' || typeUpper === 'SEND') return <ArrowUpward color="error" />;
    return <SwapHoriz color="primary" />;
  };

  if (!isAuthenticated) {
    return (
      <Box display="flex" flexDirection="column" justifyContent="center" alignItems="center" minHeight="80vh">
        <Error sx={{ fontSize: 60, color: 'error.main', mb: 2 }} />
        <Typography variant="h5" gutterBottom>
          Authentication Required
        </Typography>
        <Typography variant="body1" color="text.secondary" align="center" sx={{ mb: 3, maxWidth: 500 }}>
          Please log in to view your dashboard and access TerraFlow features.
        </Typography>
        <Button 
          variant="contained" 
          onClick={() => navigate('/login')}
        >
          Go to Login
        </Button>
      </Box>
    );
  }

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="80vh">
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Container maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
      <Grid container spacing={3}>
        {/* Welcome Section */}
        <Grid item xs={12}>
          <Paper sx={{ p: 3, display: 'flex', flexDirection: 'column' }}>
            <Typography variant="h4" gutterBottom>
              Welcome, {currentUser?.username || 'User'}
            </Typography>
            <Typography variant="body1" color="text.secondary">
              Here's an overview of your account
            </Typography>
            <Box mt={2}>
              <Typography variant="caption" color="text.secondary">
                User ID: {currentUser?.id || 'Unknown'} | Authentication: {isAuthenticated ? 'Yes' : 'No'}
              </Typography>
            </Box>
          </Paper>
        </Grid>

        {error && (
          <Grid item xs={12}>
            <Alert severity="error">{error}</Alert>
          </Grid>
        )}

        {/* Total Balance */}
        <Grid item xs={12} md={4}>
          <Paper 
            sx={{ 
              p: 2, 
              display: 'flex', 
              flexDirection: 'column',
              backgroundColor: 'primary.main',
              color: 'white'
            }}
          >
            <Typography variant="h6" gutterBottom>
              Total Balance
            </Typography>
            <Typography variant="h3" component="div" sx={{ fontWeight: 'bold' }}>
              {formatCurrency(totalBalance)}
            </Typography>
            <Typography variant="body2" sx={{ mt: 1 }}>
              Across all wallets
            </Typography>
          </Paper>
        </Grid>

        {/* Quick Actions */}
        <Grid item xs={12} md={8}>
          <Paper sx={{ p: 2, display: 'flex', flexDirection: 'column' }}>
            <Typography variant="h6" gutterBottom>
              Quick Actions
            </Typography>
            <Grid container spacing={2} sx={{ mt: 1 }}>
              <Grid item xs={6} sm={3}>
                <Button 
                  variant="outlined" 
                  fullWidth 
                  startIcon={<Send />} 
                  sx={{ p: 1 }}
                  onClick={() => navigate('/send')}
                >
                  Send
                </Button>
              </Grid>
              <Grid item xs={6} sm={3}>
                <Button 
                  variant="outlined" 
                  fullWidth 
                  startIcon={<AccountBalanceWallet />} 
                  sx={{ p: 1 }}
                  onClick={() => navigate('/wallets')}
                >
                  Wallets
                </Button>
              </Grid>
              <Grid item xs={6} sm={3}>
                <Button 
                  variant="outlined" 
                  fullWidth 
                  startIcon={<Chat />} 
                  sx={{ p: 1 }}
                  onClick={() => navigate('/nl-interface')}
                >
                  Ask AI
                </Button>
              </Grid>
              <Grid item xs={6} sm={3}>
                <Button 
                  variant="outlined" 
                  fullWidth 
                  startIcon={<Assessment />} 
                  sx={{ p: 1 }}
                  onClick={() => navigate('/analytics')}
                >
                  Analytics
                </Button>
              </Grid>
            </Grid>
          </Paper>
        </Grid>

        {/* Wallets Section */}
        <Grid item xs={12} md={6}>
          <Paper sx={{ p: 2, display: 'flex', flexDirection: 'column' }}>
            <Box display="flex" justifyContent="space-between" alignItems="center" mb={2}>
              <Typography variant="h6">Your Wallets</Typography>
              <Button 
                size="small" 
                onClick={() => navigate('/wallets')}
              >
                View All
              </Button>
            </Box>

            {wallets.length === 0 ? (
              <Box textAlign="center" py={3}>
                <Typography variant="body1" color="text.secondary">
                  You don't have any wallets yet.
                </Typography>
                <Button 
                  variant="contained" 
                  startIcon={<AccountBalanceWallet />} 
                  sx={{ mt: 2 }}
                  onClick={() => navigate('/wallets')}
                >
                  Manage Wallets
                </Button>
              </Box>
            ) : (
              <Box>
                {wallets.slice(0, 3).map((wallet) => (
                  <Card key={wallet.id} sx={{ mb: 2 }}>
                    <CardContent>
                      <Typography variant="subtitle1" gutterBottom>
                        {wallet.name || `${wallet.currency || 'USD'} Wallet`}
                      </Typography>
                      <Typography variant="h5" component="div">
                        {formatCurrency(wallet.fiat_balance || wallet.balance || 0, wallet.currency)}
                      </Typography>
                      <Typography color="text.secondary" sx={{ fontSize: 14, mt: 1 }}>
                        {wallet.wallet_address || wallet.address || 'No address available'}
                      </Typography>
                    </CardContent>
                  </Card>
                ))}
              </Box>
            )}
          </Paper>
        </Grid>

        {/* Recent Transactions */}
        <Grid item xs={12} md={6}>
          <Paper sx={{ p: 2, display: 'flex', flexDirection: 'column' }}>
            <Box display="flex" justifyContent="space-between" alignItems="center" mb={2}>
              <Typography variant="h6">Recent Transactions</Typography>
              <Button 
                size="small" 
                onClick={() => navigate('/transactions')}
              >
                View All
              </Button>
            </Box>

            {transactions.length === 0 ? (
              <Box textAlign="center" py={3}>
                <Typography variant="body1" color="text.secondary">
                  No transactions found.
                </Typography>
                <Button 
                  variant="contained" 
                  startIcon={<Send />} 
                  sx={{ mt: 2 }}
                  onClick={() => navigate('/send')}
                >
                  Send Money
                </Button>
              </Box>
            ) : (
              <List>
                {transactions.slice(0, 5).map((transaction, index) => (
                  <React.Fragment key={transaction.id || index}>
                    <ListItem alignItems="flex-start">
                      <ListItemAvatar>
                        <Avatar sx={{ bgcolor: 'background.paper' }}>
                          {getTransactionIcon(transaction.type || 'TRANSFER')}
                        </Avatar>
                      </ListItemAvatar>
                      <ListItemText
                        primary={
                          <Typography variant="subtitle2">
                            {transaction.type || 'Transfer'} - {transaction.formattedAmount || formatCurrency(transaction.source_amount || transaction.amount || 0)}
                          </Typography>
                        }
                        secondary={
                          <>
                            <Typography component="span" variant="body2" color="text.primary">
                              {transaction.status || 'Completed'}
                            </Typography>
                            {' — '}{transaction.formattedDate || formatDate(transaction.timestamp || new Date())}
                          </>
                        }
                      />
                    </ListItem>
                    <Divider variant="inset" component="li" />
                  </React.Fragment>
                ))}
              </List>
            )}
          </Paper>
        </Grid>

        {/* Show debug info in all environments while troubleshooting */}
        <Grid item xs={12}>
          <Paper sx={{ p: 2, mt: 2 }}>
            <Typography variant="h6" gutterBottom>
              Debug Information
            </Typography>
            <Box 
              component="pre" 
              sx={{ 
                p: 2, 
                backgroundColor: '#f5f5f5', 
                borderRadius: 1,
                maxHeight: '300px',
                overflow: 'auto',
                fontSize: '0.8rem'
              }}
            >
              {JSON.stringify({
                currentUser: currentUser ? { ...currentUser, id: currentUser.id } : null,
                isAuthenticated,
                loading,
                walletsCount: wallets.length,
                transactionsCount: transactions.length,
                error,
                debug
              }, null, 2)}
            </Box>
          </Paper>
        </Grid>
      </Grid>
    </Container>
  );
};

export default Dashboard;
